<?php

namespace App\Models;

class User
{
    public int $id;
    public string $name;
    public string $email;

    public function __construct(int $id, string $name, string $email)
    {
        $this->id = $id;
        $this->name = $name;
        $this->email = $email;
    }

    public function getDisplayName(): string
    {
        return $this->name;
    }
}
